import psycopg2
import json

def lambda_handler(event, context):
    conn_string = "dbname='production' user='admin' password='password' host='internal-db.us-east-1.rds.amazonaws.com'"

    try:
        conn = psycopg2.connect(conn_string)
        cursor = conn.cursor()
        
        cursor.execute("SELECT * FROM your_table")  # Replace 'your_table' with your actual table name
        results = cursor.fetchall()
        
        columns = [desc[0] for desc in cursor.description]
        json_results = [dict(zip(columns, row)) for row in results]
        
        cursor.close()
        conn.close()
        
        return {
            'statusCode': 200,
            'body': json.dumps(json_results)
        }

    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }